(function(){"use strict";const STORAGE_KEY="adniamey2000_lang";const CACHE_KEY="adniamey2000_translations";const SUPPORTED=["fr","en","ha","it"];let currentLang=localStorage.getItem(STORAGE_KEY)||"fr";let translations={};function loadTranslations(lang){const cacheKey=CACHE_KEY+"_"+lang;const cached=localStorage.getItem(cacheKey);if(cached){try{translations=JSON.parse(cached);if(translations&&translations.lang){applyTranslations(lang);return}}catch(e){localStorage.removeItem(cacheKey)}}var script=document.createElement("script");script.src="./data/"+lang+".js?_v="+Date.now();script.onload=function(){if(window._tr&&window._tr[lang]){translations=window._tr[lang];try{localStorage.setItem(cacheKey,JSON.stringify(translations))}catch(e){}applyTranslations(lang)}};script.onerror=function(){console.warn("i18n: failed to load",lang)};document.head.appendChild(script)}function t(key){if(!key)return key;const keys=key.split(".");let val=translations;for(const k of keys){if(val&&typeof val==="object"&&k in val){val=val[k]}else{return key}}return typeof val==="string"?val:key}function setTextContent(el,text){if(!el||text==null)return;el.textContent=text}function applyTranslations(lang){document.documentElement.lang=lang;document.querySelectorAll("[data-i18n]").forEach(function(el){const key=el.getAttribute("data-i18n");const translated=t(key);if(translated&&translated!==key){if(el.tagName==="META"){el.setAttribute("content",translated)}else if(el.tagName==="TITLE"){document.title=translated}else if(el.tagName==="INPUT"||el.tagName==="TEXTAREA"){el.placeholder=translated}else{setTextContent(el,translated)}}});document.querySelectorAll("[data-i18n-attr]").forEach(function(el){const val=el.getAttribute("data-i18n-attr");const parts=val.split(":");if(parts.length===2){const attr=parts[0];const key=parts[1];const translated=t(key);if(translated&&translated!==key){el.setAttribute(attr,translated)}}});document.documentElement.lang=lang;var selects=document.querySelectorAll(".lang-select");for(var i=0;i<selects.length;i++){selects[i].value=lang}document.dispatchEvent(new CustomEvent("languageChanged",{detail:{lang:lang}}))}window.switchLang=function(lang){if(!SUPPORTED.includes(lang))return;currentLang=lang;try{localStorage.setItem(STORAGE_KEY,lang)}catch(e){}loadTranslations(lang)};document.addEventListener("DOMContentLoaded",function(){var selects=document.querySelectorAll(".lang-select");for(var i=0;i<selects.length;i++){selects[i].value=currentLang}loadTranslations(currentLang)});window.__=t;window.currentLang=function(){return currentLang}})();